  coaching_execution = '{"movement_description":"Partner- or band-resisted first-step drill that overloads projection without turning sprinting into slow grinding.","setup":["Anchor a band around the athlete waist with a partner behind.","Set a 5-10 m lane and create only light-moderate tension."],"execution_steps":["Assume a 2-point start.","Drive out against the band for 3-5 explosive steps.","Partner releases or follows safely as the athlete finishes the short sprint."],"coach_cues":["Push the band, do not pull with the chest","Shins angled, hips through","Fast arms drive the legs"],"athlete_cues":["Crisp reps only","Own the positions","Rest enough to stay fast"],"breathing_cues":["Brace before high-intent effort","Exhale naturally after release or landing","Do not hold breath across repeated reps"],"common_faults":["Resistance too heavy","Athlete folding at the waist","Dragging contacts behind the hips"],"quality_gate":["Rep speed stays high","Posture/alignment matches the drill intent","No pain, limping, or protective mechanics","Athlete can explain the key cue before progressing"],"stop_signs":["Pain or sharp discomfort","Visible limp or asymmetry","Contacts become loud or slow","Athlete cannot maintain setup or spacing safely"]}'::jsonb,
