-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for speed, sprint mechanics, and quick-release power.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('wall-drill-iso-lean-march', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'Early in Movement Intelligence after Raise/Mobilize and before accelerations or sled work.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('wall-drill-fast-switch', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'Use after iso wall march and before starts when the athlete needs faster switch timing.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('a-march', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'After activation and before faster skips, dribbles, starts, or build-ups.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('a-skip', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'After A-march and before faster dribble or acceleration work.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('low-dribble-run', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'After marching/skipping and before wicket runs or build-up sprints.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('high-dribble-run', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'Use after low dribbles and before fly-in runs or wickets.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('ankling-drill', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'Use after general warm-up and before skips, dribbles, or low-level pogos.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('sprint-arm-action-switches', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Movement Intelligence/locomotion_sprint_mechanics because the athlete must learn posture, rhythm, and coordination before fatigue or high-output attempts.', 'Use before sprint drills or starts, especially for athletes who rotate, tense, or cross their arms.', 'Most common misuse: rushing the drill or turning it into conditioning instead of using it to improve mechanics and readiness.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('falling-start-10m', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Output/acceleration_start_speed because it is a freshness-sensitive speed-power drill: high intent, low volume, and full recovery are required for transfer.', 'Early Output after sprint mechanics; use before resisted starts or longer accelerations.', 'Most common misuse: turning high-intent sprint reps into conditioning. Stop when timing, posture, or relaxation drops; do not place after fatigue-heavy lifting or circuits.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('2-point-start-10-20m', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Output/acceleration_start_speed because it is a freshness-sensitive speed-power drill: high intent, low volume, and full recovery are required for transfer.', 'Use early in Output when the athlete is fresh and after a short sprint-mechanics block.', 'Most common misuse: turning high-intent sprint reps into conditioning. Stop when timing, posture, or relaxation drops; do not place after fatigue-heavy lifting or circuits.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
  ('3-point-start-10-20m', 'It targets the limiting qualities behind speed transfer: force direction, rapid stiffness, clean limb timing, and the ability to express force before fatigue changes mechanics.', 'Belongs in Output/acceleration_start_speed because it is a freshness-sensitive speed-power drill: high intent, low volume, and full recovery are required for transfer.', 'Use after 2-point starts for athletes with enough mobility, wrist comfort, and start competence.', 'Most common misuse: turning high-intent sprint reps into conditioning. Stop when timing, posture, or relaxation drops; do not place after fatigue-heavy lifting or circuits.', 'Scale by speed quality, landing/contact quality, range of motion, and tissue readiness. Regress first by reducing speed, amplitude, load, or reactive complexity.'),
