-- Speed / Sprinter Quick-Release cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'speed_sprinters_quick_release_readiness',
  NULL,
  'Speed / Sprinter Quick-Release without wrong phase intent or fatigue bleed',
  'Sprint mechanics, acceleration, max-velocity, elastic rudiments, and quick-release power must match phase intent — Skill for posture/rhythm, Output for high intent, Capacity for strength, Resilience for controlled landing/tissue work.',
  'Speed / Sprinter Quick-Release cards span sprint access mechanics, acceleration and max-velocity exposure, elastic stiffness, jump/throw power, landing control, and speed-strength tissue capacity for athletes who need fast first steps, clean mechanics, and explosive reacceleration.',
  'Speed transfer depends on posture, stiffness, timing, and tissue readiness. Poor placement, short rest, or conditioning disguised as Output raises injury risk and trains slow mechanics.',
  'Build Skill sprint mechanics before Output accelerations; use full rest on max-velocity and elastic Output work; keep Resilience landing sticks controlled; place strength/tissue cards in Capacity — not Output.',
  'Do not program max-velocity or plyometric Output after conditioning, use short-rest sprint circuits in Output, or hide fatigue work in Skill when the goal is crisp mechanics.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
